solutions.python:
class Solution:
  def parse_css(self, selector, rules):
    styles = {}
    for rule, value in rules.items():
      styles[rule] = value
    return f"{selector} {{ {', '.join(f"{k}: {styles[k]};") for k in styles} }}"
  def main(self):
    print(self.parse_css('div > p', {'border': '1px solid black', 'padding': '10px', 'margin': '10px'}))

